These require some tidying so that they can be combined.


Code
w3ya_25 &lt;- fd_2025 |&gt;
  dplyr::filter(Call == "W3YA") |&gt;
  dplyr::mutate(year = 2025) |&gt;
  dplyr::rename(`FINAL SCORE` = "Final Score",
                `TOTAL CW QSOs` = "Total CW QSOs",
                `TOTAL DIGITAL QSOs` = "Total Digital QSOs",
                `TOTAL PHONE QSOs` = "Total Phone QSOs",
                `TOTAL QSOs` = "Total QSOs",
                `BONUS POINTS` = "Bonus Points")

w3ya_24 &lt;- fd_2024 |&gt;
  dplyr::filter(Call == "W3YA") |&gt;
  dplyr::mutate(year = 2024)

w3ya_23 &lt;- fd_2023 |&gt;
  dplyr::filter(Call == "W3YA") |&gt;
  dplyr::mutate(year = 2023)

w3ya_22 &lt;- fd_2022 |&gt;
  dplyr::filter(CALL == "W3YA") |&gt;
  dplyr::mutate(year = 2022) |&gt;
  dplyr::rename(Call = CALL)

w3ya_21 &lt;- fd_2021 |&gt;
  dplyr::filter(CALL == "W3YA") |&gt;
  dplyr::mutate(year = 2021) |&gt;
  dplyr::rename(Call = CALL, 
                `Power Multiplier` = Pwr_Mult, 
                `FINAL SCORE` = Score,
                `Transmitters` = `Xmtrs`)

w3ya_20 &lt;- fd_2020 |&gt;
  dplyr::filter(CALL == "W3YA") |&gt;
  dplyr::mutate(year = 2020) |&gt;
  dplyr::rename(Call = CALL, `Power Multiplier` = `Pwr- Mult`, 
                `FINAL SCORE` = SCORE,
                `Transmitters` = `Xmtrs`)

w3ya_19 &lt;- fd_2019 |&gt;
  dplyr::filter(CALL == "W3YA") |&gt;
  dplyr::mutate(year = 2019) |&gt;
  dplyr::rename(Call = CALL,
                `Transmitters` = `Xmtrs`)

w3ya_18 &lt;- fd_2018 |&gt;
  dplyr::filter(CALL == "W3YA") |&gt;
  dplyr::mutate(year = 2018) |&gt;
  dplyr::rename(Call = CALL,
                `TOTAL QSOs` = `TOTAL QSOS`,
                `Participants` = `Number of Participants`,
                `Transmitters` = `Number of Transmitters`)

w3ya_17 &lt;- fd_2017 |&gt;
  dplyr::filter(`CALL (does not include checklogs)` == "W3YA") |&gt;
  dplyr::mutate(year = 2017) |&gt;
  dplyr::rename(Call = `CALL (does not include checklogs)`,
                `TOTAL QSOs` = `TOTAL QSOS`,
                `Participants` = `Number of Participants`,
                `Transmitters` = `Number of Transmitters`)

w3ya_16 &lt;- fd_2016 |&gt;
  dplyr::filter(CALL == "W3YA") |&gt;
  dplyr::mutate(year = 2016) |&gt;
  dplyr::rename(Call = `CALL`,
                `TOTAL QSOs` = `TOTAL QSOS`,
                `Participants` = `Number of Participants`,
                `Transmitters` = `Number of Transmitters`)

w3ya_15 &lt;- fd_2015 |&gt;
  dplyr::filter(CALL == "W3YA") |&gt;
  dplyr::mutate(year = 2015) |&gt;
  dplyr::mutate(Transmitters = as.numeric(stringr::str_extract(CLASS, pattern = "[0-9]{1}"))) |&gt;
  dplyr::rename(Call = `CALL`,
                `TOTAL QSOs` = `TOTAL QSOS`,
                `Participants` = `Number of Participants`)

