                `TOTAL QSOs` = `TOTAL QSOS`,
                `Participants` = `Number of Participants`)

w3ya_10 &lt;- fd_2010 |&gt;
  dplyr::filter(CALL == "W3YA") |&gt;
  dplyr::mutate(year = 2010) |&gt;
  dplyr::mutate(Transmitters = as.numeric(stringr::str_extract(CLASS, pattern = "[0-9]{1}"))) |&gt;
  dplyr::rename(Call = `CALL`,
                `TOTAL QSOs` = `TOTAL QSOS`,
                `Participants` = `Number of Participants`)

w3ya &lt;- purrr::list_rbind(list(w3ya_25,
                               w3ya_24, 
                               w3ya_23, 
                               w3ya_22, 
                               w3ya_21, 
                               w3ya_19,
                               w3ya_18,
                               w3ya_17,
                               w3ya_16,
                               w3ya_15,
                               w3ya_14,
                               w3ya_13,
                               w3ya_12,
                               w3ya_11,
                               w3ya_10))

w3ya &lt;- w3ya |&gt;
  dplyr::select(-c(`GOTA CALL`, `GOTA Call`, 
                   `CLUB NAME`)) |&gt;
  dplyr::rename(score = `FINAL SCORE`,
                cw_qsos = `TOTAL CW QSOs`,
                dig_qsos = `TOTAL DIGITAL QSOs`,
                ph_qsos = `TOTAL PHONE QSOs`,
                tot_qsos = `TOTAL QSOs`,
                bonus = `BONUS POINTS`,
                n_particip = `Participants`,
                n_xmtrs = `Transmitters`) |&gt;
  dplyr::select(score, cw_qsos, dig_qsos, ph_qsos, tot_qsos, bonus, n_particip, n_xmtrs, year)




Code
w3ya_26 &lt;- tibble::tibble(score = 1722,
                          cw_qsos = 0,
                          dig_qsos = 45,
                          ph_qsos = 186,
                          tot_qsos = 231,
                          bonus = 1170,
                          n_particip = 36,
                          n_xmtrs = 2,
                          year = 2026)

w3ya &lt;- rbind(w3ya, w3ya_26)



Score


Code
library(ggplot2)
w3ya |&gt;
  ggplot() +
  aes(x = year, y = score) +
  geom_point() +
  geom_line() +
  ylim(0, 9000)








Figure 3.1: Nittany ARC (W3YA) Field Day score 2010-26







QSOs


Code
qsos &lt;- w3ya |&gt;
  tidyr::pivot_longer(cols = contains("qsos"), names_to = "type", values_to = "n_qsos")




Code
qsos |&gt;
  dplyr::filter(!is.na(n_qsos)) |&gt;
  ggplot() +
  aes(x = year, y = n_qsos, color = type) +
  geom_point() +
  geom_line() 








Figure 3.2: Nittany ARC (W3YA) Field Day QSOs by mode 2010-25







Code
qsos |&gt;
  dplyr::filter(year &gt;= 2021) |&gt;
  ggplot() +
  aes(x = year, y = n_qsos, color = type) +
  geom_point() +
  geom_line() 








Figure 3.3: Nittany ARC (W3YA) Field Day QSOs by mode 2022-25







Bonus points


Code
w3ya |&gt;
  dplyr::filter(!is.na(bonus)) |&gt;
  ggplot() +
  aes(x = year, y = bonus) +
  geom_point() +
  geom_line() +
  scale_x_continuous(breaks = seq(2016, 2026, by = 1))








Figure 3.4: Nittany ARC (W3YA) Field Day bonus points 2016-25







Code
w3ya |&gt;
  dplyr::filter(!is.na(bonus)) |&gt;
  dplyr::mutate(bonus_pct = 100*bonus/score) |&gt;
  ggplot() +
  aes(x = year, y = bonus_pct) +
  geom_point() +
  geom_line() +
  scale_x_continuous(breaks = seq(2016, 2026, by = 1)) +
  ylab("Bonus points as a proportion of total points")








Figure 3.5: Nittany ARC (W3YA) Field Day bonus points as a proportion of total score 2016-25







